void array_prefix_max(int n, int *a, int *out)
/*@ With la lo
    Require
      0 <= n &&
      n <= INT_MAX &&
      Zlength(la) == n &&
      Zlength(lo) == n &&
      IntArray::full(a, n, la) *
      IntArray::full(out, n, lo)
    Ensure
      exists lr,
        Zlength(lr) == n &&
        (forall (i: Z),
          (0 <= i && i < n) =>
          lr[i] == max_list_nonempty(sublist(0, i + 1, la))) &&
        IntArray::full(a, n, la) *
        IntArray::full(out, n, lr)
*/
{
    int i;
    int cur;

    if (n == 0) {
        return;
    }

    cur = a[0];
    out[0] = cur;
    /*@ Inv exists l1,
          1 <= i && i <= n@pre &&
          i + 1 <= INT_MAX &&
          a == a@pre &&
          n == n@pre &&
          n <= INT_MAX &&
          out == out@pre &&
          n@pre == Zlength(la) &&
          n@pre == Zlength(lo) &&
          Zlength(l1) == i &&
          cur == max_list_nonempty(sublist(0, i, la)) &&
          (forall (k: Z),
            (0 <= k && k < i) =>
            l1[k] == max_list_nonempty(sublist(0, k + 1, la))) &&
          IntArray::full(a, n@pre, la) *
          IntArray::full(out, n@pre, app(l1, sublist(i, n@pre, lo)))
    */
    for (i = 1; i < n; ++i) {
        if (a[i] > cur) {
            cur = a[i];
        }
        /*@ Assert exists l1,
              1 <= i && i < n@pre &&
              i + 1 <= INT_MAX &&
              a == a@pre &&
              n == n@pre &&
              n <= INT_MAX &&
              out == out@pre &&
              n@pre == Zlength(la) &&
              n@pre == Zlength(lo) &&
              Zlength(l1) == i &&
              cur == max_list_nonempty(sublist(0, i + 1, la)) &&
              (forall (k: Z),
                (0 <= k && k < i) =>
                l1[k] == max_list_nonempty(sublist(0, k + 1, la))) &&
              IntArray::full(a, n@pre, la) *
              IntArray::full(out, n@pre, app(l1, sublist(i, n@pre, lo)))
        */
        out[i] = cur;
    }
}

{
    int i, j;

    /*@ Inv
          exists l_outer,
            0 <= i && i <= n@pre &&
            n == n@pre && a == a@pre &&
            Permutation(l, l_outer) &&
            sorted_z(sublist(n@pre - i, n@pre, l_outer)) &&
            (forall (p: Z),
              (0 <= p && p < n@pre - i) =>
              (forall (q: Z),
                (n@pre - i <= q && q < n@pre) =>
                l_outer[p] <= l_outer[q])) &&
            IntArray::full(a, n@pre, l_outer)
    */
    for (i = 0; i < n; ++i) {
        /*@ Inv
              exists l_inner,
                0 <= i && i < n@pre &&
                0 <= j && j <= n@pre - i - 1 &&
                n == n@pre && a == a@pre &&
                Permutation(l, l_inner) &&
                sorted_z(sublist(n@pre - i, n@pre, l_inner)) &&
                (forall (p: Z),
                  (0 <= p && p < n@pre - i) =>
                  (forall (q: Z),
                    (n@pre - i <= q && q < n@pre) =>
                    l_inner[p] <= l_inner[q])) &&
                (forall (k: Z),
